import styles from '../styles/accordion.module.css';

export interface AccordionItem {
  id: string;
  trigger: string;
  content: React.ReactNode;
}

export interface AccordionProps {
  items: AccordionItem[];
}

export const Accordion: React.FC<AccordionProps> = ({ items }) => {
  const [openIndex, setOpenIndex] = useState<number | null>(null);
  const [focusedIndex, setFocusedIndex] = useState<number>(0);
  const triggerRefs = useRef<(HTMLButtonElement | null)[]>([]);
  const baseId = useId();

  const handleTriggerClick = useCallback((index: number) => {
    setOpenIndex((prev) => (prev === index ? null : index));
  }, []);

  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent, index: number) => {
      let newIndex = index;

      switch (event.key) {
        case 'ArrowDown':
          event.preventDefault();
          newIndex = index < items.length - 1 ? index + 1 : 0;
          break;
        case 'ArrowUp':
          event.preventDefault();
          newIndex = index > 0 ? index - 1 : items.length - 1;
          break;
        case 'Home':
          event.preventDefault();
          newIndex = 0;
          break;
        case 'End':
          event.preventDefault();
          newIndex = items.length - 1;
          break;
        case 'Enter':
        case ' ':
          event.preventDefault();
          handleTriggerClick(index);
          return;
        default:
          return;
      }

      setFocusedIndex(newIndex);
      setOpenIndex((prev) => (prev === newIndex ? prev : null));
      triggerRefs.current[newIndex]?.focus();
    },
    [items.length, handleTriggerClick]
  );

  return (
    <div className={styles.accordion} data-testid="accordion">
      {items.map((item, index) => {
        const panelId = `${baseId}-panel-${item.id}`;
        const triggerId = `${baseId}-trigger-${item.id}`;
        const isOpen = openIndex === index;
        const isFocused = focusedIndex === index;

        return (
          <div key={item.id} className={styles.accordionItem}>
            <button
              id={triggerId}
              ref={(el) => {
                triggerRefs.current[index] = el;
              }}
              type="button"
              className={styles.accordionTrigger}
              onClick={() => handleTriggerClick(index)}
              onKeyDown={(e) => handleKeyDown(e, index)}
              aria-expanded={isOpen}
              aria-controls={panelId}
              tabIndex={isFocused ? 0 : -1}
              data-testid="accordion-trigger"
            >
              {item.trigger}
            </button>
            <div
              id={panelId}
              role="region"
              aria-labelledby={triggerId}
              className={styles.accordionPanel}
              hidden={!isOpen}
              data-testid="accordion-panel"
            >
              {isOpen && item.content}
            </div>
          </div>
        );
      })}
    </div>
  );
};

export default Accordion;
