{"type":"tool_use","timestamp":1775689898125,"sessionID":"ses_290a37e76ffetbSfqT4WgLzpuN","part":{"id":"prt_d6f5d5e7e0018oCyZh7vy3PHGB","messageID":"msg_d6f5d359d001Yx3OAQ43YWd9G1","sessionID":"ses_290a37e76ffetbSfqT4WgLzpuN","type":"tool","tool":"write","callID":"call_function_70ewdqfq6r70_1","state":{"status":"completed","input":{"content":"import React from 'react';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { Accordion } from './Accordion';

const testItems = [
  { id: 'item-1', trigger: 'Trigger 1', content: 'Content 1' },
  { id: 'item-2', trigger: 'Trigger 2', content: 'Content 2' },
  { id: 'item-3', trigger: 'Trigger 3', content: 'Content 3' },
];

describe('Accordion', () => {
  it('renders all triggers', () => {
    render(<Accordion items={testItems} />);
    expect(screen.getAllByTestId('accordion-trigger')).toHaveLength(3);
  });

  it('shows content panel when trigger is activated', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const triggers = screen.getAllByTestId('accordion-trigger');
    await user.click(triggers[0]);

    expect(triggers[0]).toHaveAttribute('aria-expanded', 'true');
    const panel = screen.getByTestId('accordion-panel');
    expect(panel).not.toHaveAttribute('hidden');
  });

  it('hides content panel when trigger is deactivated', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const triggers = screen.getAllByTestId('accordion-trigger');
    await user.click(triggers[0]);
    await user.click(triggers[0]);

    expect(triggers[0]).toHaveAttribute('aria-expanded', 'false');
  });

  it('closes other panels when a new trigger is activated', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const triggers = screen.getAllByTestId('accordion-trigger');
    await user.click(triggers[0]);
    expect(triggers[0]).toHaveAttribute('aria-expanded', 'true');

    await user.click(triggers[1]);
    expect(triggers[0]).toHaveAttribute('aria-expanded', 'false');
    expect(triggers[1]).toHaveAttribute('aria-expanded', 'true');
  });

  it('has aria-expanded on trigger reflecting open state', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const trigger = screen.getAllByTestId('accordion-trigger')[0];
    expect(trigger).toHaveAttribute('aria-expanded', 'false');

    await user.click(trigger);
    expect(trigger).toHaveAttribute('aria-expanded', 'true');
  });

  it('has aria-controls pointing to panel id', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const triggers = screen.getAllByTestId('accordion-trigger');
    const panels = screen.getAllByTestId('accordion-panel');

    expect(triggers[0]).toHaveAttribute('aria-controls');
    const controlsId = triggers[0].getAttribute('aria-controls');
    expect(panels[0]).toHaveAttribute('id', controlsId);
  });

  it('focus remains on trigger after activation', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const trigger = screen.getAllByTestId('accordion-trigger')[0];
    trigger.focus();
    await user.click(trigger);

    expect(document.activeElement).toBe(trigger);
  });

  it('roving tabindex pattern - only focused item has tabIndex 0', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const triggers = screen.getAllByTestId('accordion-trigger');

    // First trigger should be focusable initially (tabIndex 0)
    expect(triggers[0]).toHaveAttribute('tabIndex', '0');
    expect(triggers[1]).toHaveAttribute('tabIndex', '-1');
    expect(triggers[2]).toHaveAttribute('tabIndex', '-1');

    // Focus second trigger via click
    await user.click(triggers[1]);

    // After focus, second should be tabIndex 0, others -1
    expect(triggers[0]).toHaveAttribute('tabIndex', '-1');
    expect(triggers[1]).toHaveAttribute('tabIndex', '0');
    expect(triggers[2]).toHaveAttribute('tabIndex', '-1');
  });

  it('arrow keys move focus between triggers', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const triggers = screen.getAllByTestId('accordion-trigger');
    triggers[0].focus();

    expect(document.activeElement).toBe(triggers[0]);

    await user.keyboard('{ArrowDown}');
    expect(document.activeElement).toBe(triggers[1]);

    await user.keyboard('{ArrowDown}');
    expect(document.activeElement).toBe(triggers[2]);

    await user.keyboard('{ArrowDown}');
    expect(document.activeElement).toBe(triggers[0]); // wraps around
  });

  it('Home key jumps to first trigger', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const triggers = screen.getAllByTestId('accordion-trigger');
    triggers[2].focus();

    await user.keyboard('{Home}');
    expect(document.activeElement).toBe(triggers[0]);
  });

  it('End key jumps to last trigger', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const triggers = screen.getAllByTestId('accordion-trigger');
    triggers[0].focus();

    await user.keyboard('{End}');
    expect(document.activeElement).toBe(triggers[2]);
  });

  it('Enter key activates trigger', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const trigger = screen.getAllByTestId('accordion-trigger')[0];
    trigger.focus();

    await user.keyboard('{Enter}');
    expect(trigger).toHaveAttribute('aria-expanded', 'true');
  });

  it('panel visibility toggles with display none/block', async () => {
    const user = userEvent.setup();
    render(<Accordion items={testItems} />);

    const panel = screen.getAllByTestId('accordion-panel')[0];
    const trigger = screen.getAllByTestId('accordion-trigger')[0];

    // Panel should be hidden initially
    expect(panel).toHaveAttribute('hidden');

    // Click to open
    await user.click(trigger);
    expect(panel).not.toHaveAttribute('hidden');

    // Click to close
    await user.click(trigger);
    expect(panel).toHaveAttribute('hidden');
  });
});
